import{c as a,Q as o,j as t,m as n}from"./chunks/framework.CdiUUa3G.js";const h=JSON.parse('{"title":"ADR-005 — nginx + Docker Compose deployment","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-005.md","filePath":"adr/ADR-005.md"}'),i={name:"adr/ADR-005.md"};function r(s,e,l,d,c,p){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="adr-005-—-nginx-docker-compose-deployment" tabindex="-1">ADR-005 — nginx + Docker Compose deployment <a class="header-anchor" href="#adr-005-—-nginx-docker-compose-deployment" aria-label="Permalink to &quot;ADR-005 — nginx + Docker Compose deployment&quot;">​</a></h1><blockquote><p>Status · <strong>Superseded by ADR-014 (GitHub Actions + GitHub Pages)</strong> Date · 2026-04-01 · Superseded April 2026 TA anchor · §stack · §constraints</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The application needs a deployment target that is self-contained, reproducible, and runnable with a single command on any machine with Docker installed.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Single nginx:alpine container managed by Docker Compose. <code>docker compose up</code> installs and runs.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>Simplest possible deployment for a static application. No application server, no backend, no orchestration complexity. The <code>data/</code> directory is mounted as a separate volume so mission data can be updated without rebuilding the application bundle.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li>GitHub Pages / Netlify — valid for public hosting; doesn&#39;t satisfy the self-hostable, offline-capable requirement.</li><li>Serve via <code>npm run preview</code> — development only; not a production deployment.</li><li>Apache — equivalent to nginx for this use case; nginx is more commonly used for this pattern.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: single-command deploy; reproducible across environments; data updates don&#39;t require rebuild. Negative: requires Docker; adds a layer for developers who just want to open the HTML files (prototypes still work as file://).</p>',12)])])}const m=a(i,[["render",r]]);export{h as __pageData,m as default};
